#ifndef FLT_MAX
#define FLT_MAX 3.40282347e+38
#endif

// Calculate Euclidean distance squared
static float euclid_dist_2(const float *pt1, const float *pt2, int numdims) {
    float ans = 0.0f;
    for (int i = 0; i < numdims; i++) {
        float diff = pt1[i] - pt2[i];
        ans += diff * diff;
    }
    return ans;
}

// Find the nearest cluster center for a point
static int find_nearest_point(const float *pt, int nfeatures, const float *clusters, int nclusters) {
    int index = 0;
    float min_dist = FLT_MAX;

    for (int i = 0; i < nclusters; i++) {
        float dist = euclid_dist_2(pt, clusters + i * nfeatures, nfeatures);
        if (dist < min_dist) {
            min_dist = dist;
            index = i;
        }
    }
    return index;
}

// Kernel: Assign each point to the nearest cluster
__kernel void kmeans_assign(
    const float *features,
    const float *clusters,
    int *membership,
    int npoints,
    int nfeatures,
    int nclusters)
{
    int i = get_global_id(0);
    if (i >= npoints) return;

    int cluster_idx = find_nearest_point(features + i * nfeatures, nfeatures, clusters, nclusters);
    membership[i] = cluster_idx;
}

// Kernel: Accumulate sums and counts for new centers
__kernel void kmeans_accumulate(
    const float *features,
    const int *membership,
    float *new_centers,
    int *center_counts,
    int npoints,
    int nfeatures,
    int nclusters)
{
    int i = get_global_id(0);
    if (i >= npoints) return;

    int cluster_idx = membership[i];

    // Atomically increment count
    int old_count = atomic_add(&center_counts[cluster_idx], 1);

    // Atomically add feature values to the cluster sum
    // Note: atomic_add for float is supported in OpenCL 2.0 and with extensions in 1.2
    // We assume OpenCL 2.0 as per build environment (opencl>=2.0)
    for (int j = 0; j < nfeatures; j++) {
        atomic_add(&new_centers[cluster_idx * nfeatures + j], features[i * nfeatures + j]);
    }
}

// Kernel: Update centers by dividing sums by counts
__kernel void kmeans_update(
    float *clusters,
    const float *new_centers,
    const int *center_counts,
    int nclusters,
    int nfeatures)
{
    int i = get_global_id(0);
    if (i >= nclusters) return;

    int count = center_counts[i];
    if (count > 0) {
        for (int j = 0; j < nfeatures; j++) {
            clusters[i * nfeatures + j] = new_centers[i * nfeatures + j] / (float)count;
        }
    }
    // Reset count for next iteration if needed (usually done by host or separate kernel)
}

// Kernel: Initialize counts and sums to zero
__kernel void kmeans_init_accumulators(
    float *new_centers,
    int *center_counts,
    int nclusters,
    int nfeatures)
{
    int i = get_global_id(0);
    if (i >= nclusters) return;

    center_counts[i] = 0;
    for (int j = 0; j < nfeatures; j++) {
        new_centers[i * nfeatures + j] = 0.0f;
    }
}
